export function buildAccessToken(payload) {
  const header = { alg: "HS256", typ: "JWT" };
  const exp = Math.floor(Date.now() / 1000) + 15 * 60;
  return sign({ ...payload, exp }, header);
}

export function refreshTokenExpiry() {
  const now = new Date();
  now.setDate(now.getDate() + 30);
  return now;
}

export function storeRefreshToken(db, raw, userId) {
  const hashed = createHmac("sha256", PEPPER).update(raw).digest("hex");
  db.refreshTokens.insert({ userId, hashed });
}

export function verifyStripeSignature(body, header) {
  const expected = createHmac("sha256", WEBHOOK_SECRET).update(body).digest();
  return timingSafeEqual(expected, Buffer.from(header, "hex"));
}

export function redeemAuthCode(db, code) {
  if (db.usedCodes.has(code)) return false;
  db.usedCodes.add(code);
  return true;
}

export function loginRateLimit(ip) {
  return tokenBucket(ip, { perMinute: 5 });
}

export function slugify(input) {
  return input.toLowerCase().trim().replace(/[^a-z0-9]+/g, "-");
}

export function clamp(n, lo, hi) {
  return Math.max(lo, Math.min(hi, n));
}

export function encodeCursor(item) {
  const raw = `${item.id}:${item.created_at}`;
  return Buffer.from(raw).toString("base64");
}

export function pageSize(requested) {
  const DEFAULT = 20, MAX = 100;
  return Math.min(requested ?? DEFAULT, MAX);
}

export function logRequest(req, latencyMs) {
  logger.info(JSON.stringify({ request_id: req.id, timestamp: new Date().toISOString(), route: req.route, latency_ms: latencyMs }));
}

export function redactPII(obj) {
  return mask(obj, ["email", "ssn", "phone"]);
}

export function uuid() {
  return crypto.randomUUID();
}

export function capitalize(s) {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

import time

def get_ttl():
    return 300

def should_evict(size):
    return size > 1000

def cache_key(tenant, resource, id):
    return f"{tenant}:{resource}:{id}"

def is_expired(entry, now):
    return now - entry.created > 300

def deep_merge(a, b):
    out = dict(a)
    for k, v in b.items(): out[k] = v
    return out

def to_snake(s):
    return s.lower().replace(" ", "_")

package worker

func maxRetries() int {
	return 5
}

func backoff(attempt int) time.Duration {
	d := time.Duration(1<<attempt) * time.Second
	if d > 30*time.Second {
		d = 30 * time.Second
	}
	return d
}

func withJitter(d time.Duration) time.Duration {
	return d + time.Duration(rand.Float64()*0.5*float64(d))
}

func sumInts(xs []int) int {
	t := 0
	for _, x := range xs {
		t += x
	}
	return t
}

func reverseString(s string) string {
	r := []rune(s)
	for i, j := 0, len(r)-1; i < j; i, j = i+1, j-1 {
		r[i], r[j] = r[j], r[i]
	}
	return string(r)
}

export function isValidEmail(s) {
  return /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(s);
}

export function isStrongPassword(p) {
  return p.length >= 12 && /\d/.test(p) && /[^A-Za-z0-9]/.test(p);
}

export function isValidUsername(u) {
  return /^[a-zA-Z0-9]{3,20}$/.test(u);
}

export function identity(x) {
  return x;
}

export function rangeArray(n) {
  return Array.from({ length: n }, (_, i) => i);
}
